/* CBMC stub models for the C standard-library allocation functions.
   The production CBMC library models for malloc/free carry a nondeterministic
   `should_malloc_fail` flag whose late injection via `goto-instrument
   --add-library` crashes the contract-enforcement instrumentation.  These
   deterministic models give malloc/free real bodies up front so the library is
   never injected: malloc always returns a fresh object of the requested size
   (the usual CBMC default of non-failing malloc), and free releases it. */

/* FUNCTION: malloc */

void *malloc(__CPROVER_size_t size)
{
    return __CPROVER_allocate(size, 0);
}

